ult(0) // 0 to 1\n  riskIndicator String? // on_track, at_risk, delayed\n\n  // Dates\n  startDate   DateTime?\n  dueDate     DateTime?\n  completedAt DateTime?\n\n  // Notes and metadata\n  notes       String?\n  nextStep    String?\n  ceoNotes    String?\n  sourceMonth String?\n\n  // Data source tracking\n  dataSourceId String?\n  dataSource   DataSource? @relation(fields: [dataSourceId], references: [id])\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  auditLogs     TaskAuditLog[]\n  notifications Notification[]\n}\n\n// Audit log for tracking all task changes\nmodel TaskAuditLog {\n  id     String  @id @default(cuid())\n  taskId String\n  task   Task    @relation(fields: [taskId], references: [id])\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id])\n\n  action   String // create, update, delete, status_change\n  field    String? // Which field was changed\n  oldValue String?\n  newValue String?\n\n  createdAt DateTime @default(now())\n}\n\n// Data source for tracking uploaded files\nmodel DataSource {\n  id            String   @id @default(cuid())\n  fileName      String\n  originalName  String\n  fileSize      Int\n  rowCount      Int\n  columnMapping String? // JSON string of column mappings\n  uploadedById  String?\n  uploadedAt    DateTime @default(now())\n\n  tasks Task[]\n}\n\n// Notification model\nmodel Notification {\n  id     String  @id @default(cuid())\n  taskId String?\n  task   Task?   @relation(fields: [taskId], references: [id])\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id])\n\n  type    String // assignment, reminder, overdue, status_change\n  channel String // email, whatsapp\n  subject String\n  message String\n  status  String @default(\"pending\") // pending, sent, failed\n\n  scheduledAt DateTime?\n  sentAt      DateTime?\n  error       String?\n\n  createdAt DateTime @default(now())\n}\n\n// Notification rules configuration\nmodel NotificationRule {\n  id      String @id @default(cuid())\n  name    String\n  type    String // assignment, reminder, overdue, status_change\n  channel String @default(\"email\") // email, whatsapp\n\n  // Trigger conditions\n  daysBeforeDue Int? // For reminders (e.g., 3 days before)\n\n  // Recipients\n  notifyOwner    Boolean @default(true)\n  notifyAssignee Boolean @default(true)\n  notifyManager  Boolean @default(false)\n\n  // Template\n  subjectTemplate String?\n  bodyTemplate    String?\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// System configuration\nmodel SystemConfig {\n  id        String   @id @default(cuid())\n  key       String   @unique\n  value     String\n  updatedAt DateTime @updatedAt\n}\n\n// Admin notification settings\nmodel AdminSettings {\n  id String @id @default(cuid())\n\n  // Admin email for receiving reports\n  adminEmail String\n\n  // Daily digest settings\n  dailyDigestEnabled Boolean @default(false)\n  dailyDigestTime    String  @default(\"09:00\") // HH:mm format\n\n  // Weekly report settings\n  weeklyReportEnabled Boolean @default(false)\n  weeklyReportDay     Int     @default(1) // 0=Sunday, 1=Monday, etc.\n  weeklyReportTime    String  @default(\"09:00\")\n\n  // In-progress tasks report\n  inProgressReportEnabled   Boolean @default(false)\n  inProgressReportFrequency String  @default(\"daily\") // daily, weekly\n\n  // Reminder settings\n  taskReminderEnabled    Boolean @default(true)\n  overdueReminderEnabled Boolean @default(true)\n\n  // Custom reminder dates (comma-separated ISO dates)\n  customReminderDates String? // e.g., \"2024-01-15,2024-01-20,2024-01-25\"\n\n  // Days before due date for automatic reminders\n  reminderDaysBefore Int @default(3)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// Scheduled reminders with specific dates\nmodel ScheduledReminder {\n  id String @id @default(cuid())\n\n  // Reminder details\n  title       String\n  description String?\n\n  // Schedule\n  reminderDate DateTime\n  reminderTime String   @default(\"09:00\") // HH:mm format\n\n  // Recipients\n  sendToAdmin  Boolean @default(true)\n  sendToOwners Boolean @default(true)\n\n  // Task filter (optional - if set, only remind about these tasks)\n  taskIds String? // Comma-separated task IDs\n\n  // Status\n  isActive Boolean   @default(true)\n  isSent   Boolean   @default(false)\n  sentAt   DateTime?\n\n  // Email tracking\n  emailsSent   Int @default(0)\n  emailsFailed Int @default(0)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n",
